features.snippet:
wire foo;
wire bar;
logic sel;
initial begin
  case (sel)
    foo:
      $display("foo");
    bar:
      $display("bar");
    default:
      $display("default");
  endcase
end

wire [1:0] a;
wire [1:0] b;
logic [1:0] in;
always_comb begin
  case (in)
    a: out = 2'b01;
    b: out = 2'b10;
    default: out = 2'b00;
  endcase
end

integer fd;
wire pat0;
wire pat1;
logic val;
initial begin
  fd = $fopen("out.txt", "w");
  case (val)
    pat0: $fwrite(fd, "matched pat0\n");
    pat1: $fwrite(fd, "matched pat1\n");
    default: $fwrite(fd, "default\n");
  endcase
  $fclose(fd);
end
